import { defineSchema, defineTable } from "convex/server";
import { v } from "convex/values";

export default defineSchema({
  messages: defineTable({
    body: v.string(),
    author: v.string(),
    channelId: v.string(),
  }).searchIndex("search_body", {
    searchField: "body",
    filterFields: ["channelId"],
  }),
});

import { v } from "convex/values";
import { mutation, query } from "./_generated/server";
import { paginationOptsValidator } from "convex/server";

export const insert = mutation({
  args: {
    body: v.string(),
    author: v.string(),
    channelId: v.string(),
  },
  handler: async (ctx, args) => {
    await ctx.db.insert("messages", {
      body: args.body,
      author: args.author,
      channelId: args.channelId,
    });
  },
});

export const search = query({
  args: {
    query: v.string(),
    channelId: v.string(),
    paginationOpts: paginationOptsValidator,
  },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("messages")
      .withSearchIndex("search_body", (q) =>
        q.search("body", args.query).eq("channelId", args.channelId)
      )
      .paginate(args.paginationOpts);
  },
});

const { ConvexHttpClient } = require("convex/browser");
const { api } = require("./convex/_generated/api");

async function main() {
  const args = process.argv.slice(2);
  const runIdIndex = args.indexOf("--run-id");
  if (runIdIndex === -1 || !args[runIdIndex + 1]) {
    console.error("Usage: node test.js --run-id <run-id>");
    process.exit(1);
  }
  const runId = args[runIdIndex + 1];

  const convexUrl = process.env.CONVEX_URL;
  if (!convexUrl) {
    console.error("CONVEX_URL environment variable is not set");
    process.exit(1);
  }

  const client = new ConvexHttpClient(convexUrl);

  // 2. Insert 3 messages
  await client.mutation(api.messages.insert, {
    body: "Hello world",
    author: "Alice",
    channelId: runId,
  });
  await client.mutation(api.messages.insert, {
    body: "Hello Convex",
    author: "Bob",
    channelId: runId,
  });
  await client.mutation(api.messages.insert, {
    body: "Hello search",
    author: "Charlie",
    channelId: runId,
  });

  // 3. Wait for the search index to update
  let results;
  for (let i = 0; i < 20; i++) {
    results = await client.query(api.messages.search, {
      query: "Hello",
      channelId: runId,
      paginationOpts: { numItems: 2, cursor: null },
    });
    if (results.page.length >= 2) {
      break;
    }
    await new Promise((resolve) => setTimeout(resolve, 1000));
  }

  // 5. Print the page array
  console.log(JSON.stringify(results.page));
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
